end

function LxShopHandler:OnShopRefreshResp(pb)
    local shopObj = ModuleCenter.Shop:SetShopObj(pb.shopObj)
    FireEvent(EventNames.SHOP_REFRESH_RESULT, shopObj)
    CtrlCenter.City:RefreshShopInfo()
end

function LxShopHandler:OnShopListResp(pb)
